using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.RegularExpressions;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to your OpenAI API key.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- Shared state ---
var researchNotes = new List<(string Title, string Content)>();
using var httpClient = new HttpClient();
httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");
httpClient.Timeout = TimeSpan.FromSeconds(15);

// ---------------------------------------------------------------------------
// Tool: SearchWeb – queries DuckDuckGo HTML and returns the top results.
// ---------------------------------------------------------------------------
[Description("Search the web for information on a query. Returns titles, URLs, and snippets.")]
async Task<string> SearchWeb(
    [Description("The search query to look up")] string query)
{
    try
    {
        var encoded = Uri.EscapeDataString(query);
        var html = await httpClient.GetStringAsync(
            $"https://html.duckduckgo.com/html/?q={encoded}");

        var sb = new StringBuilder();
        var pattern = new Regex(
            @"<a[^>]*class=""result__a""[^>]*href=""([^""]*?)""[^>]*>(.*?)</a>" +
            @".*?<a[^>]*class=""result__snippet""[^>]*>(.*?)</a>",
            RegexOptions.Singleline);

        int count = 0;
        foreach (Match m in pattern.Matches(html))
        {
            if (++count > 5) break;
            var title = Regex.Replace(
                WebUtility.HtmlDecode(m.Groups[2].Value), "<.*?>", "").Trim();
            var url = WebUtility.HtmlDecode(m.Groups[1].Value);
            var snippet = Regex.Replace(
                WebUtility.HtmlDecode(m.Groups[3].Value), "<.*?>", "").Trim();

            sb.AppendLine($"[{count}] {title}");
            sb.AppendLine($"    URL: {url}");
            sb.AppendLine($"    {snippet}");
            sb.AppendLine();
        }

        return count > 0
            ? sb.ToString()
            : "No results found. Try rephrasing the query.";
    }
    catch (Exception ex)
    {
        return $"Search failed: {ex.Message}. Try a different query.";
    }
}

// ---------------------------------------------------------------------------
// Tool: SaveNote – persists a research finding for later summarisation.
// ---------------------------------------------------------------------------
[Description("Save a research note with a title and content. Use to record important findings.")]
string SaveNote(
    [Description("A short descriptive title for the note")] string title,
    [Description("The detailed content of the note")] string content)
{
    researchNotes.Add((title, content));
    return $"Note saved: \"{title}\" ({researchNotes.Count} total)";
}

// ---------------------------------------------------------------------------
// Tool: GetAllNotes – retrieves every note taken so far.
// ---------------------------------------------------------------------------
[Description("Retrieve all saved research notes so you can review findings before summarising.")]
string GetAllNotes()
{
    if (researchNotes.Count == 0)
        return "No notes saved yet.";

    var sb = new StringBuilder();
    for (int i = 0; i < researchNotes.Count; i++)
    {
        sb.AppendLine($"--- Note {i + 1}: {researchNotes[i].Title} ---");
        sb.AppendLine(researchNotes[i].Content);
        sb.AppendLine();
    }
    return sb.ToString();
}

// --- Register tools ---
var tools = new List<AITool>
{
    AIFunctionFactory.Create(SearchWeb),
    AIFunctionFactory.Create(SaveNote),
    AIFunctionFactory.Create(GetAllNotes),
};

// --- Create the MEAI chat client (provider-agnostic abstraction) ---
IChatClient chatClient = new OpenAI.Chat.ChatClient(modelId, apiKey)
    .AsIChatClient();

// --- Create the research agent (handles tool dispatch automatically) ---
var agent = new ChatClientAgent(
    chatClient: chatClient,
    instructions: """
        You are a thorough research agent. When given a topic to research:

        1. Use the SearchWeb tool with varied queries to explore different angles of the topic.
        2. Save important findings using SaveNote — include specific facts, data, and source URLs.
        3. Perform at least 3 different searches to get comprehensive coverage.
        4. Call GetAllNotes to review your collected findings before writing the summary.
        5. Produce a well-structured final summary that includes:
           - A concise overview paragraph
           - Key findings organised by theme
           - Sources cited with URLs where available

        Be factual, concise, and thorough. Prioritise credible sources.
        """,
    name: "ResearchAgent",
    description: "Researches topics via web search and note-taking, then summarises findings",
    tools: tools);

// --- Run options with guardrails ---
var runOptions = new ChatClientAgentRunOptions
{
    ChatOptions = new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 4096,
    },
};

// --- Interactive loop ---
Console.WriteLine("╔═══════════════════════════════════════════╗");
Console.WriteLine("║          🔍  AI Research Agent            ║");
Console.WriteLine("║   Enter a topic to research, or 'quit'   ║");
Console.WriteLine("╚═══════════════════════════════════════════╝");
Console.WriteLine();

while (true)
{
    Console.Write("Topic: ");
    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic) ||
        topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
    {
        break;
    }

    researchNotes.Clear();
    Console.WriteLine($"\n🔎 Researching: {topic}\n");

    try
    {
        await foreach (var update in agent.RunStreamingAsync(
            $"Research the following topic and provide a comprehensive summary: {topic}",
            session: null,
            options: runOptions))
        {
            if (!string.IsNullOrEmpty(update.Text))
                Console.Write(update.Text);
        }

        Console.WriteLine();
        Console.WriteLine();
    }
    catch (Exception ex)
    {
        Console.WriteLine($"\n❌ Error: {ex.Message}\n");
    }
}

Console.WriteLine("Goodbye! 👋");

